const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

if (!SENDGRID_API_KEY || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_PHONE_NUMBER) {
  throw new Error('Missing required environment variables for email and SMS services');
}

sgMail.setApiKey(SENDGRID_API_KEY);

const client = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendNotification = async (req, res) => {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { to, type, message, subject } = req.body;

  if (!to || !type || !message) {
    return res.status(400).json({ error: 'Missing required fields: to, type, message' });
  }

  if (type !== 'email' && type !== 'sms') {
    return res.status(400).json({ error: 'Invalid message type. Must be "email" or "sms"' });
  }

  try {
    if (type === 'email') {
      const email = {
        to,
        from: 'noreply@yourapp.com',
        subject: subject || 'Notification',
        text: message,
        html: `<p>${message}</p>`,
      };

      await sgMail.send(email);
    } else if (type === 'sms') {
      await client.messages.create({
        body: message,
        from: TWILIO_PHONE_NUMBER,
        to,
      });
    }

    res.status(200).json({ success: true, message: 'Message sent successfully' });
  } catch (error) {
    console.error('Error sending message:', error);
    res.status(500).json({ error: 'Failed to send message' });
  }
};